const OUTPUT_DIR = path.join(__dirname, 'seed-data')

interface GrammarExercise {
  title: string; description: string; level: string; category: string
  question: string; options: string[]; correct_answer: string
  explanation: string; order_index: number
}

interface VocabItem {
  german_word: string; english_translation: string; article: string | null
  plural: string | null; example_sentence: string; level: string; category: string
}

const grammarExercises: GrammarExercise[] = []

function addEx(level: string, cat: string, title: string, desc: string, q: string, opts: string[], correct: string, explanation: string, idx: number) {
  grammarExercises.push({ title, description: desc, level, category: cat, question: q, options: opts, correct_answer: correct, explanation, order_index: idx })
}

